// webp
function testWebP(callback) {
   var webP = new Image();
   webP.onload = webP.onerror = function () {
      callback(webP.height == 2);
   };
   webP.src = 'data:image/webp;base64,UklGRjoAAABXRUJQVlA4IC4AAACyAgCdASoCAAIALmk0mk0iIiIiIgBoSygABc6WWgAA/veff/0PP8bA//LwYAAA';
}
testWebP(function (support) {
   if (support == true) {
      document.querySelector('body').classList.add('webp');
   } else {
      document.querySelector('body').classList.add('no-webp');
   }
});
// burger
function burgerMenu() {
   const burger = document.querySelector('.burger')
   const nav = document.querySelector('.nav')
   const body = document.querySelector('body')
   burger.addEventListener('click', () => {
      if (!nav.classList.contains('active')) {
         nav.classList.add('active')
         burger.classList.add('active')
         body.classList.add('locked')
      } else {
         nav.classList.remove('active')
         burger.classList.remove('active')
         body.classList.remove('locked')
      }
   })
   if (document.querySelector('body.items')) {
      const itemsBurger = document.querySelector('.items__burger')
      const itemsMenu = document.querySelector('.items__aside')
      itemsBurger.addEventListener('click', () => {
         if (!itemsMenu.classList.contains('active')) {
            itemsMenu.classList.add('active')
            itemsBurger.classList.add('active')
         } else {
            itemsMenu.classList.remove('active')
            itemsBurger.classList.remove('active')
         }
      })
   }
}
burgerMenu();
