if (document.querySelector('body.katalog')) {
   let btnItem = document.querySelectorAll('.katalog__item')
   for (let i = 0; i < btnItem.length; i++) {
      let btnShop = btnItem[i].querySelector('.btn-shop')
      let btnCount = btnItem[i].querySelector(".btn-form")
      let input = btnItem[i].querySelector('.btn__form-input')
      let plus = btnItem[i].querySelector('.plus')
      let minus = btnItem[i].querySelector('.minus')
      btnShop.addEventListener('click', () => {
         if (btnShop.classList.contains('hidden')) {
            btnShop.classList.remove('hidden')
         } else {
            btnShop.classList.add('hidden')
            btnCount.classList.add('show')
         }
      })
      plus.addEventListener('click', () => {
         input.value++
      })
      minus.addEventListener('click', () => {
         input.value--
      })
   }
}
