if (document.querySelector('body.accordion')) {
   function accordion() {
      const items = document.querySelectorAll('.accordion__header')
      items.forEach(item => {
         item.addEventListener('click', () => {
            const parent = item.parentNode
            if (parent.classList.contains('show')) {
               parent.classList.remove('show')
            } else {
               document
                  .querySelectorAll('.accordion__item')
                  .forEach(child => child.classList.remove('show'))
               parent.classList.add('show')
            }
         })
      })
   }
   accordion()
}
if (document.querySelector('body.items')) {
   //
   var lowerSlider = document.querySelector('#lower'),
      upperSlider = document.querySelector('#upper'),
      lowerVal = parseInt(lowerSlider.value);
   upperVal = parseInt(upperSlider.value);

   upperSlider.oninput = function () {
      lowerVal = parseInt(lowerSlider.value);
      upperVal = parseInt(upperSlider.value);

      if (upperVal < lowerVal + 4) {
         lowerSlider.value = upperVal - 4;

         if (lowerVal == lowerSlider.min) {
            upperSlider.value = 4;
         }
      }
   };
   lowerSlider.oninput = function () {
      lowerVal = parseInt(lowerSlider.value);
      upperVal = parseInt(upperSlider.value);

      if (lowerVal > upperVal - 4) {
         upperSlider.value = lowerVal + 4;

         if (upperVal == upperSlider.max) {
            lowerSlider.value = parseInt(upperSlider.max) - 4;
         }

      }
   };
   //
   var x, i, j, l, ll, selElmnt, a, b, c;
   x = document.getElementsByClassName('items__aside-select');
   l = x.length;
   for (i = 0; i < l; i++) {
      selElmnt = x[i].getElementsByTagName('select')[0];
      ll = selElmnt.length;
      a = document.createElement('DIV');
      a.setAttribute('class', 'items__aside-selected text');
      a.innerHTML = selElmnt.options[selElmnt.selectedIndex].innerHTML;
      x[i].appendChild(a);
      b = document.createElement('DIV');
      b.setAttribute('class', 'items__aside-content items__aside-hide text');
      for (j = 1; j < ll; j++) {
         c = document.createElement('DIV');
         c.innerHTML = selElmnt.options[j].innerHTML;
         c.addEventListener('click', function (e) {
            var y, i, k, s, h, sl, yl;
            s = this.parentNode.parentNode.getElementsByTagName('select')[0];
            sl = s.length;
            h = this.parentNode.previousSibling;
            for (i = 0; i < sl; i++) {
               if (s.options[i].innerHTML == this.innerHTML) {
                  s.selectedIndex = i;
                  h.innerHTML = this.innerHTML;
                  y = this.parentNode.getElementsByClassName('same-as-selected');
                  yl = y.length;
                  for (k = 0; k < yl; k++) {
                     y[k].removeAttribute('class');
                  }
                  this.setAttribute('class', 'same-as-selected text');
                  break;
               }
            }
            h.click();
         });
         b.appendChild(c);
      }
      x[i].appendChild(b);
      a.addEventListener('click', function (e) {
         e.stopPropagation();
         closeAllSelect(this);
         this.nextSibling.classList.toggle('items__aside-hide');
         this.classList.toggle('items__aside-arrow');
      });
   }
   function closeAllSelect(elmnt) {
      var x, y, i, xl, yl, arrNo = [];
      x = document.getElementsByClassName('items__aside-content');
      y = document.getElementsByClassName('items__aside-selected');
      xl = x.length;
      yl = y.length;
      for (i = 0; i < yl; i++) {
         if (elmnt == y[i]) {
            arrNo.push(i)
         } else {
            y[i].classList.remove('items__aside-arrow');
         }
      }
      for (i = 0; i < xl; i++) {
         if (arrNo.indexOf(i)) {
            x[i].classList.add('items__aside-hide');
         }
      }
   }
   document.addEventListener('click', closeAllSelect);
}